#include<bits/stdc++.h>
#define int long long
using namespace std;
int k,n,e,d;
signed main(){
	cin>>k;
	for(int i=1;i<=k;i++){
		cin>>n>>e>>d;
		int gjr1=n-e*d+2;
		if(gjr1<0){
			cout<<"NO"<<"\n";
			continue;
		}
		int gjr2=gjr1*gjr1;
		gjr2-=4*n;
		if(gjr2==sqrt(gjr2)*sqrt(gjr2)){
			gjr2=sqrt(gjr2);
			cout<<(gjr1-gjr2)/2<<' '<<gjr2+(gjr1-gjr2)/2<<"\n";
		}else{
			cout<<"NO"<<"\n";
		}
	}
	return 0;
}
